function applyClockTowerZhFixes(chapter) {
  const fixes = CLOCK_TOWER_ZH_BLOCK_FIXES[chapter.no];
  if (!fixes?.length) return chapter;
  const zh = clockTowerBlocks(chapter.zh);
  [...fixes].sort((a, b) => b.index - a.index).forEach(fix => {
    const insert = fix.texts || (Object.prototype.hasOwnProperty.call(fix, "text") ? [fix.text] : []);
    zh.splice(fix.index, fix.count, ...insert);
  });
  return { ...chapter, zh: zh.join("\n\n") };
}

