function applyClockTowerSemanticFixes(chapter) {
  const fixes = CLOCK_TOWER_ZH_SEMANTIC_FIXES[chapter.no];
  if (!fixes?.length) return chapter;
  const zh = clockTowerBlocks(chapter.zh);
  [...fixes].sort((a, b) => b.index - a.index).forEach(fix => {
    const insert = fix.texts || (Object.prototype.hasOwnProperty.call(fix, "text") ? [fix.text] : []);
    zh.splice(fix.index, fix.count, ...insert);
  });
  return { ...chapter, zh: zh.join("\n\n") };
}

CLOCK_TOWER_NOVEL.chapters = CLOCK_TOWER_NOVEL.chapters
  .map(applyClockTowerZhFixes)
  .map(applyClockTowerFinalZhFixes)
  .map(applyClockTowerSemanticFixes);

CLOCK_TOWER_NOVEL.chapters.forEach(chapter => {
  chapter.vocab = CLOCK_TOWER_VOCAB[chapter.no] || chapter.vocab || [];
  chapter.quiz = CLOCK_TOWER_QUIZ[chapter.no] || chapter.quiz || [];
});
